import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useApp } from '../../context/AppContext';

export default function LoginPage() {
  const { dispatch } = useApp();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    setError('');
    if (!form.email || !form.password) { setError('Vui lòng điền đầy đủ thông tin'); return; }

    setLoading(true);
    setTimeout(() => {
      // Check registered users
      const users = JSON.parse(localStorage.getItem('health_users') || '[]');
      const found = users.find(u => u.email === form.email && u.password === form.password);
      if (!found) {
        setError('Email hoặc mật khẩu không đúng');
        setLoading(false);
        return;
      }
      dispatch({ type: 'LOGIN', payload: { email: found.email, name: found.name } });
      // load that user's profile
      const profile = JSON.parse(localStorage.getItem(`health_profile_${found.email}`) || 'null');
      if (profile) dispatch({ type: 'SET_PROFILE', payload: profile });
      navigate('/dashboard');
    }, 800);
  };

  return (
    <div style={styles.page}>
      <div style={styles.bg} />
      <div style={styles.card}>
        {/* Logo */}
        <div style={styles.logo}>
          <div style={styles.logoIcon}>♥</div>
          <div>
            <div style={styles.logoName}>VitaTrack</div>
            <div style={styles.logoSub}>Health Monitor</div>
          </div>
        </div>

        <h1 style={styles.title}>Đăng nhập</h1>
        <p style={styles.sub}>Chào mừng trở lại! Theo dõi sức khỏe của bạn.</p>

        <form onSubmit={handleSubmit} style={styles.form}>
          <div className="input-group">
            <label className="input-label">Email</label>
            <input
              type="email"
              className="input-field"
              placeholder="your@email.com"
              value={form.email}
              onChange={e => setForm({ ...form, email: e.target.value })}
            />
          </div>
          <div className="input-group">
            <label className="input-label">Mật khẩu</label>
            <input
              type="password"
              className="input-field"
              placeholder="••••••••"
              value={form.password}
              onChange={e => setForm({ ...form, password: e.target.value })}
            />
          </div>

          {error && <div style={styles.error}>{error}</div>}

          <button type="submit" className="btn btn-primary" style={{ width: '100%', marginTop: 8 }} disabled={loading}>
            {loading ? <span style={styles.spinner} /> : null}
            {loading ? 'Đang đăng nhập...' : 'Đăng nhập'}
          </button>
        </form>

        <p style={styles.switchText}>
          Chưa có tài khoản?{' '}
          <Link to="/register" style={styles.link}>Đăng ký ngay</Link>
        </p>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: 20,
    position: 'relative',
  },
  bg: {
    position: 'fixed',
    inset: 0,
    background: 'radial-gradient(ellipse at 20% 50%, rgba(0,212,255,0.08) 0%, transparent 60%), radial-gradient(ellipse at 80% 20%, rgba(168,85,247,0.06) 0%, transparent 60%)',
    pointerEvents: 'none',
  },
  card: {
    background: 'rgba(22,29,46,0.9)',
    backdropFilter: 'blur(20px)',
    border: '1px solid rgba(255,255,255,0.08)',
    borderRadius: 24,
    padding: '40px 36px',
    width: '100%',
    maxWidth: 420,
    position: 'relative',
    zIndex: 1,
    animation: 'fadeInUp 0.5s ease',
    boxShadow: '0 24px 80px rgba(0,0,0,0.5)',
  },
  logo: {
    display: 'flex', alignItems: 'center', gap: 12, marginBottom: 32,
  },
  logoIcon: {
    width: 44, height: 44,
    background: 'linear-gradient(135deg, #00d4ff, #0099cc)',
    borderRadius: 12,
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    fontSize: 22, color: '#000', fontWeight: 800,
    boxShadow: '0 4px 20px rgba(0,212,255,0.3)',
  },
  logoName: {
    fontFamily: 'var(--font-display)', fontWeight: 800, fontSize: 18,
    color: '#f0f4ff',
  },
  logoSub: { fontSize: 11, color: '#4a5568', textTransform: 'uppercase', letterSpacing: '1px' },
  title: {
    fontFamily: 'var(--font-display)', fontSize: 28, fontWeight: 800,
    color: '#f0f4ff', marginBottom: 6,
  },
  sub: { fontSize: 14, color: '#8892aa', marginBottom: 28 },
  form: { display: 'flex', flexDirection: 'column', gap: 16 },
  error: {
    background: 'rgba(255,79,139,0.1)',
    border: '1px solid rgba(255,79,139,0.3)',
    borderRadius: 10, padding: '10px 14px',
    fontSize: 13, color: '#ff4f8b',
  },
  spinner: {
    display: 'inline-block',
    width: 16, height: 16,
    border: '2px solid rgba(0,0,0,0.3)',
    borderTopColor: '#000',
    borderRadius: '50%',
    animation: 'spin 0.8s linear infinite',
  },
  switchText: { textAlign: 'center', marginTop: 24, fontSize: 14, color: '#8892aa' },
  link: { color: '#00d4ff', textDecoration: 'none', fontWeight: 600 },
};
